sys_script_email.script:
(function runMailScript(
    /* GlideRecord */
    current,
    /* TemplatePrinter */
    template,
    /* Optional EmailOutbound */
    email,
    /* Optional GlideRecord */
    email_action,
    /* Optional GlideRecord */
    event
) {
    var userSysId = EmailHelpers.getUserSysId(event, current);

    var userAccess = new UserAccess();
    userAccess.setUser(userSysId);
    var isAdmin = userAccess.isAdmin();

    if (isAdmin) {
        template.print(
            '<p class="content-footer" style="margin: 0; margin-bottom: 5px; text-align: center; font-family: \'Roboto\',sans-serif; font-weight: 400; font-size: 10px; color: #666666;">' +
            'Have questions? Call us at 1-800-579-2848 or email ' +
            '<a href="mailto:enterprise-pkisupport@digicert.com" style="text-decoration: underline; color: #666666; font-family: \'Roboto\', sans-serif; font-size: 10px; text-align: center;">enterprise-pkisupport@digicert.com</a>' +
            '</p>'
        );
    }
})(current, template, email, email_action, event);
